import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, CircleMarker, Popup } from "react-leaflet";
import "leaflet/dist/leaflet.css";
import { getPredictions } from "../services/api";

export default function MapView() {
  const [predictions, setPredictions] = useState([]);
  const [loading, setLoading]         = useState(true);

  useEffect(() => {
    getPredictions()
      .then(res => { setPredictions(res.data.predictions || []); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  const getColor = (fill) => fill >= 80 ? "#e74c3c" : fill >= 60 ? "#f39c12" : "#2ecc71";

  if (loading) return <div style={{ textAlign: "center", padding: "40px" }}>⏳ Loading map...</div>;

  return (
    <div>
      <h2 style={{ marginTop: 0, color: "#1a5276" }}>🗺️ Bin Locations — Buea</h2>

      {/* LEGEND */}
      <div style={{ display: "flex", gap: "16px", marginBottom: "16px", flexWrap: "wrap" }}>
        {[["🟢 Below 60% — OK", "#2ecc71"], ["🟡 60–80% — Monitor", "#f39c12"], ["🔴 Above 80% — Urgent", "#e74c3c"]].map(([label, color]) => (
          <div key={label} style={{ display: "flex", alignItems: "center", gap: "8px", background: "white", padding: "8px 16px", borderRadius: "20px", boxShadow: "0 1px 4px rgba(0,0,0,0.1)" }}>
            <div style={{ width: "14px", height: "14px", borderRadius: "50%", background: color }} />
            <span style={{ fontSize: "13px" }}>{label}</span>
          </div>
        ))}
      </div>

      {/* MAP */}
      <div style={{ borderRadius: "12px", overflow: "hidden", boxShadow: "0 2px 8px rgba(0,0,0,0.15)" }}>
        <MapContainer
          center={[4.1534, 9.2916]}
          zoom={14}
          style={{ height: "520px", width: "100%" }}
        >
          <TileLayer
            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
            attribution="© OpenStreetMap contributors"
          />
          {predictions.map((bin, i) => (
            <CircleMarker
              key={i}
              center={[bin.lat, bin.lon]}
              radius={bin.needs_collection ? 14 : 10}
              fillColor={getColor(bin.predicted_fill)}
              color="white"
              weight={2}
              fillOpacity={0.85}
            >
              <Popup>
                <div style={{ minWidth: "180px" }}>
                  <strong>{bin.name}</strong><br />
                  <span style={{ color: "#666" }}>{bin.neighborhood}</span><br /><br />
                  <span>Fill Level: </span>
                  <strong style={{ color: getColor(bin.predicted_fill) }}>
                    {bin.predicted_fill}%
                  </strong><br />
                  <span>Capacity: {bin.capacity_kg} kg</span><br />
                  <span>{bin.is_market_area ? "🏪 Market Area" : "🏘️ Residential"}</span><br /><br />
                  {bin.needs_collection
                    ? <span style={{ color: "#e74c3c", fontWeight: "bold" }}>⚠️ Needs Collection</span>
                    : <span style={{ color: "#2ecc71" }}>✅ OK</span>
                  }
                </div>
              </Popup>
            </CircleMarker>
          ))}
        </MapContainer>
      </div>
    </div>
  );
}
